const pptxgen = require("pptxgenjs");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const sharp = require("sharp");

// Icon imports
const { FaRobot, FaGraduationCap, FaBrain, FaCode, FaCloud, FaFlask, FaRocket, FaLayerGroup, FaCertificate, FaUsers, FaChartLine, FaTerminal, FaLightbulb, FaCheckCircle, FaArrowRight, FaCogs, FaDatabase, FaShieldAlt, FaPlay, FaStar, FaBookOpen, FaLaptopCode } = require("react-icons/fa");
const { MdSmartToy, MdSchool, MdAutoFixHigh, MdTimeline, MdTrendingUp, MdQuestionAnswer } = require("react-icons/md");
const { HiLightningBolt, HiChip } = require("react-icons/hi");

// ── Color Palette (KodeKloud Dark Theme) ──
const C = {
  bg: "0B1120",
  bgLight: "111B2E",
  card: "151E33",
  cardLight: "1A2540",
  cyan: "00D4AA",
  cyanDark: "00A888",
  white: "FFFFFF",
  ice: "CADCFC",
  muted: "8899BB",
  accent2: "3B82F6",  // blue accent
  accent3: "A855F7",  // purple accent
  accent4: "F59E0B",  // amber accent
  accent5: "EF4444",  // red accent
  green: "10B981",
};

// ── Icon Renderer ──
function renderIconSvg(IconComponent, color = "#FFFFFF", size = 256) {
  return ReactDOMServer.renderToStaticMarkup(
    React.createElement(IconComponent, { color, size: String(size) })
  );
}
async function iconToBase64(IconComponent, color, size = 256) {
  const svg = renderIconSvg(IconComponent, color, size);
  const buf = await sharp(Buffer.from(svg)).png().toBuffer();
  return "image/png;base64," + buf.toString("base64");
}

// ── Helper Factories ──
const mkShadow = () => ({ type: "outer", blur: 8, offset: 3, angle: 135, color: "000000", opacity: 0.25 });
const mkCardShadow = () => ({ type: "outer", blur: 6, offset: 2, angle: 135, color: "000000", opacity: 0.2 });

// ── Shared footer ──
function addFooter(slide, slideNum, total) {
  slide.addText(`KodeKloud  •  Cohort Presentation  •  March 2026`, {
    x: 0.5, y: 5.25, w: 7, h: 0.3, fontSize: 8, color: C.muted, fontFace: "Calibri"
  });
  slide.addText(`${slideNum} / ${total}`, {
    x: 8, y: 5.25, w: 1.5, h: 0.3, fontSize: 8, color: C.muted, fontFace: "Calibri", align: "right"
  });
}

// ── Accent bar at top ──
function addTopBar(slide) {
  slide.addShape("rect", { x: 0, y: 0, w: 10, h: 0.04, fill: { color: C.cyan } });
}

async function buildPresentation() {
  const pres = new pptxgen();
  pres.layout = "LAYOUT_16x9";
  pres.author = "Michael & Mumshad";
  pres.title = "The AI-Powered DevOps Engineer – KodeKloud Cohort Presentation";

  const TOTAL = 20;
  let sn = 0;

  // Pre-render icons
  const icons = {
    robot: await iconToBase64(FaRobot, "#00D4AA"),
    brain: await iconToBase64(FaBrain, "#00D4AA"),
    grad: await iconToBase64(FaGraduationCap, "#FFFFFF"),
    code: await iconToBase64(FaCode, "#00D4AA"),
    cloud: await iconToBase64(FaCloud, "#3B82F6"),
    flask: await iconToBase64(FaFlask, "#A855F7"),
    rocket: await iconToBase64(FaRocket, "#F59E0B"),
    layer: await iconToBase64(FaLayerGroup, "#00D4AA"),
    cert: await iconToBase64(FaCertificate, "#F59E0B"),
    users: await iconToBase64(FaUsers, "#00D4AA"),
    chart: await iconToBase64(FaChartLine, "#10B981"),
    terminal: await iconToBase64(FaTerminal, "#00D4AA"),
    bulb: await iconToBase64(FaLightbulb, "#F59E0B"),
    check: await iconToBase64(FaCheckCircle, "#10B981"),
    arrow: await iconToBase64(FaArrowRight, "#00D4AA"),
    cogs: await iconToBase64(FaCogs, "#CADCFC"),
    db: await iconToBase64(FaDatabase, "#3B82F6"),
    shield: await iconToBase64(FaShieldAlt, "#EF4444"),
    play: await iconToBase64(FaPlay, "#00D4AA"),
    star: await iconToBase64(FaStar, "#F59E0B"),
    book: await iconToBase64(FaBookOpen, "#00D4AA"),
    laptop: await iconToBase64(FaLaptopCode, "#00D4AA"),
    smarttoy: await iconToBase64(MdSmartToy, "#A855F7"),
    school: await iconToBase64(MdSchool, "#00D4AA"),
    autofix: await iconToBase64(MdAutoFixHigh, "#00D4AA"),
    timeline: await iconToBase64(MdTimeline, "#3B82F6"),
    trending: await iconToBase64(MdTrendingUp, "#10B981"),
    qa: await iconToBase64(MdQuestionAnswer, "#00D4AA"),
    lightning: await iconToBase64(HiLightningBolt, "#F59E0B"),
    chip: await iconToBase64(HiChip, "#A855F7"),
    robotWhite: await iconToBase64(FaRobot, "#FFFFFF"),
    brainCyan: await iconToBase64(FaBrain, "#00D4AA"),
    cyanCheck: await iconToBase64(FaCheckCircle, "#00D4AA"),
  };

  // ════════════════════════════════════════════════════════
  // SLIDE 1: TITLE
  // ════════════════════════════════════════════════════════
  {
    sn++;
    const s = pres.addSlide();
    s.background = { color: C.bg };
    // Large gradient-like overlay block
    s.addShape("rect", { x: 0, y: 0, w: 10, h: 5.625, fill: { color: C.bg } });
    // Decorative shapes
    s.addShape("rect", { x: 0, y: 0, w: 10, h: 0.06, fill: { color: C.cyan } });
    s.addShape("rect", { x: 0, y: 5.565, w: 10, h: 0.06, fill: { color: C.cyan } });
    // Side accent
    s.addShape("rect", { x: 0, y: 1.2, w: 0.06, h: 3.2, fill: { color: C.cyan } });

    s.addImage({ data: icons.robot, x: 0.6, y: 0.6, w: 0.7, h: 0.7 });

    s.addText("The AI-Powered\nDevOps Engineer", {
      x: 0.6, y: 1.4, w: 8.5, h: 1.8, fontSize: 42, fontFace: "Calibri",
      color: C.white, bold: true, lineSpacingMultiple: 1.1, margin: 0
    });
    s.addText("Your Learning Journey at KodeKloud", {
      x: 0.6, y: 3.2, w: 8, h: 0.6, fontSize: 22, fontFace: "Calibri",
      color: C.cyan, margin: 0
    });
    s.addText("Cohort Presentation  •  March 2026", {
      x: 0.6, y: 3.9, w: 5, h: 0.4, fontSize: 14, fontFace: "Calibri", color: C.muted, margin: 0
    });
    s.addText("Presented by Michael & Mumshad", {
      x: 0.6, y: 4.4, w: 5, h: 0.4, fontSize: 13, fontFace: "Calibri", color: C.ice, margin: 0
    });
  }

  // ════════════════════════════════════════════════════════
  // SLIDE 2: THE DEVOPS ROLE IS EVOLVING
  // ════════════════════════════════════════════════════════
  {
    sn++;
    const s = pres.addSlide();
    s.background = { color: C.bg };
    addTopBar(s);

    s.addText("The DevOps Role Is Evolving", {
      x: 0.6, y: 0.35, w: 9, h: 0.7, fontSize: 32, fontFace: "Calibri",
      color: C.white, bold: true, margin: 0
    });
    s.addText("AI isn't replacing DevOps engineers — it's expanding what they can do", {
      x: 0.6, y: 1.05, w: 8.5, h: 0.4, fontSize: 14, fontFace: "Calibri", color: C.cyan, margin: 0
    });

    // Three evolution cards
    const evCards = [
      { icon: icons.cogs, title: "Traditional DevOps", desc: "Manual pipelines, scripted automation, reactive monitoring, human-driven troubleshooting", color: C.muted },
      { icon: icons.lightning, title: "AI-Enhanced DevOps", desc: "AI-assisted coding, intelligent monitoring, predictive alerting, automated remediation", color: C.accent2 },
      { icon: icons.smarttoy, title: "Agentic DevOps", desc: "Autonomous agents, self-healing systems, MCP tool integration, multi-agent orchestration", color: C.cyan },
    ];
    evCards.forEach((c, i) => {
      const cx = 0.5 + i * 3.1;
      s.addShape("rect", { x: cx, y: 1.7, w: 2.9, h: 2.9, fill: { color: C.card }, shadow: mkCardShadow() });
      s.addShape("rect", { x: cx, y: 1.7, w: 2.9, h: 0.06, fill: { color: c.color } });
      s.addImage({ data: c.icon, x: cx + 0.2, y: 1.95, w: 0.45, h: 0.45 });
      s.addText(c.title, { x: cx + 0.2, y: 2.5, w: 2.5, h: 0.4, fontSize: 15, fontFace: "Calibri", color: C.white, bold: true, margin: 0 });
      s.addText(c.desc, { x: cx + 0.2, y: 2.95, w: 2.5, h: 1.3, fontSize: 11, fontFace: "Calibri", color: C.ice, margin: 0 });
    });

    s.addText("The question isn't IF you need AI skills — it's HOW FAST you can build them", {
      x: 0.6, y: 4.85, w: 8.5, h: 0.35, fontSize: 12, fontFace: "Calibri", color: C.muted, italic: true, margin: 0
    });
    addFooter(s, sn, TOTAL);
  }

  // ════════════════════════════════════════════════════════
  // SLIDE 3: THREE LAYERS OF AI AT KODEKLOUD
  // ════════════════════════════════════════════════════════
  {
    sn++;
    const s = pres.addSlide();
    s.background = { color: C.bg };
    addTopBar(s);

    s.addText("Three Layers of AI at KodeKloud", {
      x: 0.6, y: 0.35, w: 9, h: 0.7, fontSize: 32, fontFace: "Calibri",
      color: C.white, bold: true, margin: 0
    });

    const layers = [
      { num: "1", title: "Learn AI as a Skill", desc: "37+ courses, 2 learning paths, 5 certification preps", icon: icons.book, accent: C.cyan },
      { num: "2", title: "Learn WITH AI", desc: "AI Assistant, AI Tutor, KodeKey multi-LLM API, personalized paths", icon: icons.autofix, accent: C.accent2 },
      { num: "3", title: "Practice in Real Environments", desc: "9 AI playgrounds: AWS Bedrock, Azure OpenAI, Claude Code, MCP, n8n", icon: icons.flask, accent: C.accent3 },
    ];

    layers.forEach((l, i) => {
      const cy = 1.35 + i * 1.35;
      s.addShape("rect", { x: 0.5, y: cy, w: 9, h: 1.15, fill: { color: C.card }, shadow: mkCardShadow() });
      s.addShape("rect", { x: 0.5, y: cy, w: 0.08, h: 1.15, fill: { color: l.accent } });
      // Number circle
      s.addShape("oval", { x: 0.85, y: cy + 0.25, w: 0.6, h: 0.6, fill: { color: l.accent } });
      s.addText(l.num, { x: 0.85, y: cy + 0.25, w: 0.6, h: 0.6, fontSize: 20, fontFace: "Calibri", color: C.bg, bold: true, align: "center", valign: "middle", margin: 0 });
      s.addImage({ data: l.icon, x: 1.7, y: cy + 0.28, w: 0.5, h: 0.5 });
      s.addText(l.title, { x: 2.4, y: cy + 0.15, w: 6.5, h: 0.45, fontSize: 18, fontFace: "Calibri", color: C.white, bold: true, margin: 0 });
      s.addText(l.desc, { x: 2.4, y: cy + 0.6, w: 6.5, h: 0.4, fontSize: 12, fontFace: "Calibri", color: C.ice, margin: 0 });
    });

    s.addText("KodeKloud's brand has evolved: DevOps & Cloud → DevOps, Cloud & AI", {
      x: 0.6, y: 4.85, w: 8.5, h: 0.35, fontSize: 12, fontFace: "Calibri", color: C.muted, italic: true, margin: 0
    });
    addFooter(s, sn, TOTAL);
  }

  // ════════════════════════════════════════════════════════
  // SLIDE 4: LAYER 1 SECTION BREAK
  // ════════════════════════════════════════════════════════
  {
    sn++;
    const s = pres.addSlide();
    s.background = { color: C.card };
    s.addShape("rect", { x: 0, y: 0, w: 10, h: 0.06, fill: { color: C.cyan } });
    s.addShape("rect", { x: 0, y: 5.565, w: 10, h: 0.06, fill: { color: C.cyan } });

    s.addShape("oval", { x: 4.25, y: 1.0, w: 1.5, h: 1.5, fill: { color: C.cyan, transparency: 15 } });
    s.addImage({ data: icons.book, x: 4.5, y: 1.25, w: 1, h: 1 });

    s.addText("Layer 1", { x: 1, y: 2.7, w: 8, h: 0.5, fontSize: 16, fontFace: "Calibri", color: C.cyan, align: "center", margin: 0 });
    s.addText("Learn AI as a Skill", { x: 1, y: 3.1, w: 8, h: 0.8, fontSize: 36, fontFace: "Calibri", color: C.white, bold: true, align: "center", margin: 0 });
    s.addText("37+ courses  •  2 learning paths  •  5 certifications  •  Hands-on labs", {
      x: 1, y: 3.9, w: 8, h: 0.4, fontSize: 14, fontFace: "Calibri", color: C.ice, align: "center", margin: 0
    });
  }

  // ════════════════════════════════════════════════════════
  // SLIDE 5: AI LEARNING PATH (19 COURSES)
  // ════════════════════════════════════════════════════════
  {
    sn++;
    const s = pres.addSlide();
    s.background = { color: C.bg };
    addTopBar(s);

    s.addText("The AI Learning Path", {
      x: 0.6, y: 0.3, w: 7, h: 0.6, fontSize: 28, fontFace: "Calibri", color: C.white, bold: true, margin: 0
    });
    s.addText("19 courses  •  Beginner → Specialist", {
      x: 0.6, y: 0.85, w: 6, h: 0.35, fontSize: 13, fontFace: "Calibri", color: C.cyan, margin: 0
    });

    const tiers = [
      { tier: "Beginner", courses: "Introduction to OpenAI (6h 38m)\nPrompt Engineering 101 (5h, 100% labs)", color: C.green },
      { tier: "Intermediate", courses: "AI-Assisted Development • GitHub Copilot Cert\nCursor AI • Cline • Claude Code\nMCP for Beginners", color: C.accent2 },
      { tier: "Cloud Certs", courses: "AWS AI Practitioner (AIF-C01)\nAzure AI-900 Fundamentals\nAzure AI-102 Engineer Associate", color: C.accent4 },
      { tier: "Advanced", courses: "Running Local LLMs with Ollama\nK8sGPT & AI-Driven K8s Engineering", color: C.accent3 },
      { tier: "Specialist", courses: "LangChain • PyTorch • AI Agents\nMastering GenAI with OpenAI\nNVIDIA GenAI LLMs Associate", color: C.accent5 },
    ];

    tiers.forEach((t, i) => {
      const cy = 1.4 + i * 0.78;
      s.addShape("rect", { x: 0.5, y: cy, w: 9, h: 0.68, fill: { color: C.card } });
      s.addShape("rect", { x: 0.5, y: cy, w: 0.06, h: 0.68, fill: { color: t.color } });
      s.addText(t.tier, { x: 0.75, y: cy + 0.05, w: 1.8, h: 0.58, fontSize: 12, fontFace: "Calibri", color: t.color, bold: true, valign: "middle", margin: 0 });
      s.addText(t.courses, { x: 2.6, y: cy + 0.05, w: 6.6, h: 0.58, fontSize: 10, fontFace: "Calibri", color: C.ice, valign: "middle", margin: 0 });
    });

    addFooter(s, sn, TOTAL);
  }

  // ════════════════════════════════════════════════════════
  // SLIDE 6: AIOPS LEARNING PATH
  // ════════════════════════════════════════════════════════
  {
    sn++;
    const s = pres.addSlide();
    s.background = { color: C.bg };
    addTopBar(s);

    s.addText("AIOps — Learn By Doing Path", {
      x: 0.6, y: 0.3, w: 7, h: 0.6, fontSize: 28, fontFace: "Calibri", color: C.white, bold: true, margin: 0
    });
    s.addText("Purpose-built for DevOps engineers entering AI-enhanced operations", {
      x: 0.6, y: 0.85, w: 8, h: 0.35, fontSize: 13, fontFace: "Calibri", color: C.cyan, margin: 0
    });

    const steps = [
      { num: "1", title: "AIOps Foundations", desc: "Intelligent monitoring with Prometheus & Grafana" },
      { num: "2", title: "Applied ML for AIOps", desc: "Anomaly detection, log clustering, time-series forecasting" },
      { num: "3", title: "Automated Remediation", desc: "Python-based auto-healing workflows" },
      { num: "4", title: "AIOps in Practice", desc: "Logging and alerting at production scale" },
      { num: "5", title: "Advanced AIOps", desc: "Distributed tracing with OpenTelemetry & Jaeger" },
      { num: "6", title: "MLOps for AIOps", desc: "MLflow & Kubeflow production pipelines" },
    ];

    steps.forEach((st, i) => {
      const col = i % 3;
      const row = Math.floor(i / 3);
      const cx = 0.5 + col * 3.1;
      const cy = 1.45 + row * 1.65;

      s.addShape("rect", { x: cx, y: cy, w: 2.9, h: 1.4, fill: { color: C.card }, shadow: mkCardShadow() });
      s.addShape("oval", { x: cx + 0.15, y: cy + 0.15, w: 0.5, h: 0.5, fill: { color: C.cyan } });
      s.addText(st.num, { x: cx + 0.15, y: cy + 0.15, w: 0.5, h: 0.5, fontSize: 16, fontFace: "Calibri", color: C.bg, bold: true, align: "center", valign: "middle", margin: 0 });
      s.addText(st.title, { x: cx + 0.8, y: cy + 0.15, w: 1.9, h: 0.45, fontSize: 13, fontFace: "Calibri", color: C.white, bold: true, valign: "middle", margin: 0 });
      s.addText(st.desc, { x: cx + 0.15, y: cy + 0.75, w: 2.6, h: 0.5, fontSize: 10.5, fontFace: "Calibri", color: C.ice, margin: 0 });
    });

    // Arrow flow indicators
    s.addText("→", { x: 3.45, y: 1.7, w: 0.3, h: 0.4, fontSize: 20, color: C.cyan, align: "center", valign: "middle" });
    s.addText("→", { x: 6.55, y: 1.7, w: 0.3, h: 0.4, fontSize: 20, color: C.cyan, align: "center", valign: "middle" });
    s.addText("→", { x: 3.45, y: 3.35, w: 0.3, h: 0.4, fontSize: 20, color: C.cyan, align: "center", valign: "middle" });
    s.addText("→", { x: 6.55, y: 3.35, w: 0.3, h: 0.4, fontSize: 20, color: C.cyan, align: "center", valign: "middle" });

    addFooter(s, sn, TOTAL);
  }

  // ════════════════════════════════════════════════════════
  // SLIDE 7: CERTIFICATION PREP
  // ════════════════════════════════════════════════════════
  {
    sn++;
    const s = pres.addSlide();
    s.background = { color: C.bg };
    addTopBar(s);

    s.addText("AI Certification Prep", {
      x: 0.6, y: 0.3, w: 7, h: 0.6, fontSize: 28, fontFace: "Calibri", color: C.white, bold: true, margin: 0
    });
    s.addText("5 industry certifications with mock exams and hands-on labs", {
      x: 0.6, y: 0.85, w: 8, h: 0.35, fontSize: 13, fontFace: "Calibri", color: C.cyan, margin: 0
    });

    const certs = [
      { name: "AWS Certified AI Practitioner", code: "AIF-C01", hours: "~6h", provider: "AWS", color: C.accent4 },
      { name: "Azure AI Fundamentals", code: "AI-900", hours: "~4h 10m", provider: "Microsoft", color: C.accent2 },
      { name: "Azure AI Engineer Associate", code: "AI-102", hours: "~7h 28m", provider: "Microsoft", color: C.accent2 },
      { name: "GenAI LLMs Associate", code: "Cert", hours: "Varies", provider: "NVIDIA", color: C.green },
      { name: "GitHub Copilot Certification", code: "Cert", hours: "~5h 34m", provider: "GitHub", color: C.white },
    ];

    certs.forEach((c, i) => {
      const cy = 1.4 + i * 0.75;
      s.addShape("rect", { x: 0.5, y: cy, w: 9, h: 0.62, fill: { color: C.card } });
      s.addShape("rect", { x: 0.5, y: cy, w: 0.06, h: 0.62, fill: { color: c.color } });
      s.addText(c.provider, { x: 0.75, y: cy + 0.05, w: 1.3, h: 0.52, fontSize: 11, fontFace: "Calibri", color: c.color, bold: true, valign: "middle", margin: 0 });
      s.addText(c.name, { x: 2.1, y: cy + 0.05, w: 4.5, h: 0.52, fontSize: 13, fontFace: "Calibri", color: C.white, valign: "middle", margin: 0 });
      s.addText(c.code, { x: 6.7, y: cy + 0.05, w: 1.2, h: 0.52, fontSize: 11, fontFace: "Calibri", color: C.muted, valign: "middle", align: "center", margin: 0 });
      s.addText(c.hours, { x: 8, y: cy + 0.05, w: 1.2, h: 0.52, fontSize: 11, fontFace: "Calibri", color: C.ice, valign: "middle", align: "right", margin: 0 });
    });

    s.addShape("rect", { x: 0.5, y: 4.45, w: 9, h: 0.5, fill: { color: C.cardLight } });
    s.addImage({ data: icons.star, x: 0.7, y: 4.5, w: 0.35, h: 0.35 });
    s.addText("AWS AI Practitioner also available as a guided cohort program", {
      x: 1.2, y: 4.45, w: 7, h: 0.5, fontSize: 12, fontFace: "Calibri", color: C.ice, valign: "middle", margin: 0
    });

    addFooter(s, sn, TOTAL);
  }

  // ════════════════════════════════════════════════════════
  // SLIDE 8: CUTTING-EDGE & AGENTIC COURSES
  // ════════════════════════════════════════════════════════
  {
    sn++;
    const s = pres.addSlide();
    s.background = { color: C.bg };
    addTopBar(s);

    s.addText("Agentic DevOps & Cutting-Edge AI", {
      x: 0.6, y: 0.3, w: 9, h: 0.6, fontSize: 28, fontFace: "Calibri", color: C.white, bold: true, margin: 0
    });
    s.addText("New courses tracking the bleeding edge of AI in DevOps", {
      x: 0.6, y: 0.85, w: 8, h: 0.35, fontSize: 13, fontFace: "Calibri", color: C.cyan, margin: 0
    });

    const courses = [
      { name: "AI Agents", desc: "Autonomous agents, multi-agent systems, Claude API, K8s MCP" },
      { name: "Building AI Agents with Claude Agent SDK", desc: "Production agent frameworks with Anthropic" },
